// Supabase Pro plan is $25/mo (2500 cents). Prorate daily = 25/30 ≈ 83 cents/day.
// This is an approximation; reconcile against the actual monthly invoice.
const daysInMonth = new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0).getDate();
const dailyPortion = Math.round(2500 / daysInMonth);  // cents
const tracking_date = new Date(Date.now() - 86400000).toISOString().slice(0,10);
return { json: { row: { tracking_date, service_name: 'supabase', spend_cents: dailyPortion, data_source: 'manual', usage_metrics: { plan: 'pro', monthly_base_cents: 2500, days_in_month: daysInMonth }, notes: 'Prorated daily portion of fixed Pro-plan base ($25/mo). For variable overages, edit this row manually after invoice arrives or use the budget-update endpoint.' } } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
return { json: { ok: true, service: 'supabase', tracking_date: row.tracking_date, spend_cents: row.spend_cents, usage: row.usage_metrics } };
